def inject_tooltips(text):
    terms = {
        "สภาร่างรัฐธรรมนูญ": "สภาร่างรัฐธรรมนูญจำลองชุดพิเศษที่มาจากการเลือกตั้งของประชาชนโดยตรง มีหน้าที่เขียนกฎหมายเพื่อผลประโยชน์ของพลเมือง",
        "ถอดถอน (Recall)": "กระบวนการให้ผู้มีสิทธิเลือกตั้งตั้งแต่ ๕,๐๐๐ คนร่วมกันเข้าชื่อเพื่อยื่นลงประชามติถอดถอนผู้แทนราษฎรหรือผู้ดำรงตำแหน่งทางการเมือง",
        "ประชามติ": "การลงประชามติของประชาชนผู้เป็นเจ้าของอำนาจอธิปไตย เพื่อเป็นข้อยุติสุดท้ายทางกฎหมายและนโยบายระดับชาติ",
        "ยึดอำนาจการปกครอง": "การทำรัฐประหารหรือฉีกรัฐธรรมนูญ โดยบทบัญญัตินี้ถือเป็นคดีกบฏที่ไม่ยอมรับการนิรโทษกรรมและไม่มีอายุความ",
        "ดิจิทัล": "สิทธิความมั่นคงไซเบอร์ ข้อมูลส่วนบุคคล และสิทธิความเป็นส่วนตัวจากการดักจับหรือสอดแนมการสื่อสารของรัฐ"
    }
    parts = re.split(r'(<[^>]+>)', text)
    for i in range(len(parts)):
        if i % 2 == 0:
            for term, desc in terms.items():
                tooltip_html = f'<span class="tooltip">{term}<span class="tooltiptext">{desc}</span></span>'
                parts[i] = parts[i].replace(term, tooltip_html)
    return ''.join(parts)

def inject_cross_references(text, current_num=None):
    parts = re.split(r'(<[^>]+>)', text)
    thai_to_arabic = {'๐':'0','๑':'1','๒':'2','๓':'3','๔':'4','๕':'5','๖':'6','๗':'7','๘':'8','๙':'9'}
    pattern = r'((?:มาตรา|ม\.)\s*([๐-๙]+))'
    for i in range(len(parts)):
        if i % 2 == 0:
            def replace_ref(match):
                full_match = match.group(1)
                thai_digits = match.group(2)
                arabic_num = ''.join(thai_to_arabic.get(d, d) for d in thai_digits)
                if current_num is not None and str(current_num) == arabic_num:
                    return full_match
                return f'<span class="cross-ref" data-target="{arabic_num}">{full_match}</span>'
            parts[i] = re.sub(pattern, replace_ref, parts[i])
    return ''.join(parts)


