def render_article_html(item):
    label = esc(item['label'])
    origin_key = item['origin']
    origin_label, badge_class = ORIGIN_LABELS.get(origin_key, ORIGIN_LABELS['original'])
    
    content = item['content']
    lines = content.split('\n')
    
    parts = []
    first_line = esc(lines[0].strip()) if lines else ''
    first_line_processed = inject_cross_references(inject_tooltips(first_line), current_num=item['num'])
    parts.append(f'<p class="article-text"><span class="art-num">{label}</span> {first_line_processed}</p>')
    
    for line in lines[1:]:
        line = line.strip()
        if not line:
            continue
        lm = re.match(r'^(\([๐-๙]+\))\s*(.*)', line)
        if lm:
            num, txt = lm.groups()
            processed_txt = inject_cross_references(inject_tooltips(esc(txt)), current_num=item['num'])
            parts.append(f'<p class="list-item"><span class="list-num">{esc(num)}</span> {processed_txt}</p>')
        else:
            processed_line = inject_cross_references(inject_tooltips(esc(line)), current_num=item['num'])
            parts.append(f'<p class="sub-para">{processed_line}</p>')
    
    body_html = '\n'.join(parts)
    
    # Check if there is a comparison
    comp_html = ""
    comp_btn = ""
    if origin_key == 'modified':
        comp = get_article_comparison(item['num'])
        if comp:
            orig_text, mod_text = comp
            comp_btn = f'<button class="compare-btn" onclick="toggleCompare(this, {item["num"]})">⚖️ เปรียบเทียบ</button>'
            comp_html = f'''
  <div class="compare-container" id="compare_{item['num']}" style="display:none;">
    <div class="compare-pane compare-original">
      <h4>📄 ฉบับดั้งเดิม (รธน. ๒๕๔๐)</h4>
      <div class="compare-text">{orig_text}</div>
    </div>
    <div class="compare-pane compare-modified">
      <h4>✨ ฉบับแก้ไขใหม่ (รธน. ๒๕๒๕)</h4>
      <div class="compare-text">{mod_text}</div>
    </div>
  </div>'''
    
    return f'''<div class="article-card" id="art_{item['num']}" data-origin="{origin_key}">
  <div class="article-header">
    <span class="badge {badge_class}">{origin_label}</span>
    {comp_btn}
  </div>
  <div class="article-body">{body_html}</div>
  {comp_html}
</div>'''

# Render chapters for nav
nav_items = [
    '<a href="#history_and_pms" class="nav-chapter active" onclick="closeSidebar()">🏛️ ประวัติศาสตร์ & ทำเนียบนายกฯ</a>'
]
for ch in chapters:
    first_art = ''
    last_art = ''
    for it in ch['items']:
        if it['type'] == 'article':
            if not first_art:
                first_art = str(it['num'])
            last_art = str(it['num'])
    range_str = f" (ม.{to_thai(int(first_art))}-{to_thai(int(last_art))})" if first_art else ""
    short = ch['title'][:40] + ('...' if len(ch['title']) > 40 else '')
    nav_items.append(f'<a href="#{ch["id"]}" class="nav-chapter" onclick="closeSidebar()">{esc(short)}{range_str}</a>')
nav_html = '\n'.join(nav_items)

# Render body
body_sections = []
for ch in chapters:
    _, badge_class = ORIGIN_LABELS.get(ch['zone'], ORIGIN_LABELS['original'])
    items_html = []
    
    # Calculate stats badges
    art_list = [it for it in ch['items'] if it['type'] == 'article']
    total_arts = len(art_list)
    modified_arts = len([it for it in art_list if it['origin'] == 'modified'])
    
    stats_badges = []
    if total_arts > 0:
        stats_badges.append(f'<span class="badge badge-stat-total">รวม {to_thai(total_arts)} มาตรา</span>')
    if modified_arts > 0:
        stats_badges.append(f'<span class="badge badge-stat-modified">แก้ไขใหม่ {to_thai(modified_arts)} มาตรา</span>')
    elif total_arts > 0 and ch['zone'] == 'original':
        stats_badges.append(f'<span class="badge badge-stat-original">คงเดิมทั้งหมด</span>')
        
    stats_html = f'<div class="chapter-stats">{" ".join(stats_badges)}</div>' if stats_badges else ''

    for it in ch['items']:
        if it['type'] == 'article':
            items_html.append(render_article_html(it))
        elif it['type'] == 'part':
            lines = [esc(l.strip()) for l in it['text'].split('\n') if l.strip()]
            items_html.append(f'<div class="part-title">{"<br>".join(lines)}</div>')
        elif it['type'] == 'signature':
            items_html.append('<div class="signature">ผู้รับสนองพระบรมราชโองการ<br><strong>นายกรัฐมนตรี</strong></div>')
        elif it['type'] == 'text':
            items_html.append(f'<div class="normal-text">{esc(it["text"])}</div>')
    
    body_sections.append(f'''<section class="chapter-section" id="{ch['id']}">
  <div class="chapter-heading"><h2>{esc(ch['title'])}</h2>{stats_html}</div>
  {''.join(items_html)}
</section>''')

all_body = '\n'.join(body_sections)

