# Render PM table rows
def format_pm_name_html(name, is_bold):
    main_name = name
    sub_name = ""
    
    # Find parenthesis like (พระยามโนปกรณ์นิติธาดา)
    m_paren = re.search(r'\s*\((.*?)\)', name)
    if m_paren:
        sub_name = f"({m_paren.group(1)})"
        main_name = name.replace(m_paren.group(0), "").strip()
    # Find quotes like "ไอติม" or “ไอติม” or \"ไอติม\"
    else:
        m_quote = re.search(r'[\"“](.*?)[\"”]', name)
        if m_quote:
            sub_name = f"({m_quote.group(1)})"
            main_name = name.replace(m_quote.group(0), "").replace("  ", " ").strip()
            
    main_esc = esc(main_name)
    sub_esc = esc(sub_name)
    
    if is_bold:
        main_html = f"<strong>{main_esc}</strong>"
    else:
        main_html = main_esc
        
    if sub_esc:
        return f'{main_html}<br><span style="font-size: 11.5px; font-weight: normal; color: var(--text-muted); opacity: 0.85; display: block; margin-top: 2px;">{sub_esc}</span>'
    return main_html

